import React from 'react';
import { Link, withRouter } from 'react-router-dom';

const IG_URL = 'https://www.instagram.com/awong.photo/';

const InstagramIcon = ({ size = 13 }) => (
  <svg
    viewBox="0 0 24 24" width={size} height={size}
    fill="none" stroke="currentColor" strokeWidth="1.6"
    strokeLinecap="round" strokeLinejoin="round"
    aria-hidden="true" style={{ verticalAlign: '-2px', marginLeft: 4 }}
  >
    <rect x="3" y="3" width="18" height="18" rx="5" />
    <circle cx="12" cy="12" r="4" />
    <circle cx="17.5" cy="6.5" r="1" fill="currentColor" stroke="none" />
  </svg>
);

const LABELS = {
  '/tinkering': 'Tinkering',
  '/work': 'Work',
  '/coffee': 'Coffee',
  '/photography': 'Photography',
  '/now': 'Now',
  '/contact': 'Contact',
};

const Nav = ({ location }) => {
  const label = LABELS[location.pathname];
  return (
    <header className="nav">
      <Link to="/" className="home">Home</Link>
      {label && (
        <span className="crumb-wrap">
          <span className="sep" aria-hidden="true">/</span>
          <span className="crumb">{label}</span>
        </span>
      )}
    </header>
  );
};

export { InstagramIcon, IG_URL };
export default withRouter(Nav);



